def bubble_sort(arr):
    n = len(arr)
    for i in range(n):
        for j in range(0, n-i-1):
            if arr[j] > arr[j+1]:  # This should be < for descending sort
                arr[j], arr[j+1] = arr[j+1], arr[j]
    return arr

def quick_sort(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[0]
    less_than_pivot = [x for x in arr[1:] if x < pivot]  # Incorrect comparison for descending
    greater_than_pivot = [x for x in arr[1:] if x >= pivot]
    return quick_sort(greater_than_pivot) + [pivot] + quick_sort(less_than_pivot)
